mapper.sql:
SELECT
ID,
COMPANY_NAME,
COMPANY_ID,
SYS_INVOICE_CODE,
INVOICE_CODE,
CUSTOMER_ID,
CUSTOMER_NAME,
INVOICE_AMOUNT,
STATUS,
INVOICE,
INVOICE_TYPE_CODE,
INVOICE_TYPE_NAME,
TAXATION_INVOICE,
TAXATION_INVOICE_CODE,
INVOICE_TIME,
REMARK,
CREATE_BY,
CREATE_BY_NAME,
CREATE_TIME,
UPDATE_BY,
UPDATE_BY_NAME,
UPDATE_TIME
FROM
T_FD_INVOICE


        and ID = #{id}


        and COMPANY_NAME = #{companyName}


        and COMPANY_ID = #{companyId}


        and SYS_INVOICE_CODE = #{sysInvoiceCode}


        and INVOICE_CODE = #{invoiceCode}


        and CUSTOMER_ID = #{customerId}


        and CUSTOMER_NAME = #{customerName}


        and INVOICE_AMOUNT = #{invoiceAmount}


        and STATUS = #{status}


        and INVOICE_TYPE_CODE = #{invoiceTypeCode}


        and INVOICE_TYPE_NAME = #{invoiceTypeName}


        and TAXATION_INVOICE = #{taxationInvoice}


        and TAXATION_INVOICE_CODE = #{taxationInvoiceCode}


        and INVOICE_TIME = #{invoiceTime}


        and REMARK = #{remark}


ORDER BY CREATE_TIME DESC

mapper.select:
SELECT * FROM( SELECT ID, HAS_NOT_RECEIPT_AMOUNT, IS_DEBTORPAYMENT, DEBTORPAYMENT_ID, COMPANY_NAME, COMPANY_ID, SYS_INVOICE_CODE, INVOICE_CODE, CUSTOMER_ID, CUSTOMER_NAME, INVOICE_AMOUNT, STATUS, INVOICE, INVOICE_TYPE_CODE, INVOICE_TYPE_NAME, TAXATION_INVOICE, TAXATION_INVOICE_CODE, INVOICE_TIME, REMARK, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME, RED_STATUS, RED_STATUS_LABEL, REGEXP_REPLACE ( LISTAGG (TO_CHAR(SHIPVOYAGE_ITEM_ID), ',') WITHIN GROUP (ORDER BY SHIPVOYAGE_ITEM_ID), '([^,]+)(,\1)+', '\1' ) SHIPVOYAGE_ITEM_ID, REGEXP_REPLACE ( LISTAGG (TO_CHAR("shipNameVoyage"), ',') WITHIN GROUP (ORDER BY "shipNameVoyage"), '([^,]+)(,\1)+', '\1' ) "shipNameVoyage" FROM ( SELECT t.ID, t.COMPANY_NAME, t.COMPANY_ID, t.SYS_INVOICE_CODE, t.INVOICE_CODE, t.CUSTOMER_ID, t.CUSTOMER_NAME, t.INVOICE_AMOUNT, t.STATUS, t.INVOICE, t.INVOICE_TYPE_CODE, t.INVOICE_TYPE_NAME, t.TAXATION_INVOICE, t.TAXATION_INVOICE_CODE, t.INVOICE_TIME, t.REMARK, t.CREATE_BY, t.CREATE_BY_NAME, t.CREATE_TIME, t.UPDATE_BY, t.UPDATE_BY_NAME, t.UPDATE_TIME, t.RED_STATUS, t.RED_STATUS_LABEL, t3.SHIPVOYAGE_ITEM_ID, t.DEBTORPAYMENT_ID, t.HAS_NOT_RECEIPT_AMOUNT, case when nvl(t.HAS_NOT_RECEIPT_AMOUNT,0) != nvl(t.INVOICE_AMOUNT,0) and t.INVOICE_AMOUNT is not null then '1' else '0' end IS_DEBTORPAYMENT, CONCAT(CONCAT(t4.SHIP_NAME, '_'),t5.VOYAGE) as "shipNameVoyage" FROM T_FD_INVOICE t LEFT JOIN T_FD_INVOICE_DETAIL t1 ON t1.INVOICE_ID = t.ID LEFT JOIN T_COST_STATEMENT_DETAIL t2 ON t1.STATEMENT_DETAIL_ID = t2.ID LEFT JOIN T_COST_STATEMENT t3 ON t3.ID = t2.STATEMENT LEFT JOIN T_DIS_SHIPVOYAGE t4 ON t3.SHIPVOYAGE_ID = t4.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM t5 ON t3.SHIPVOYAGE_ITEM_ID = t5.ID
and t.ID = #{id}
and t.COMPANY_NAME = #{companyName}
and t.CREATE_BY_NAME like #{createByNameLike}
and t.COMPANY_ID = #{companyId}
and t.SYS_INVOICE_CODE LIKE #{sysInvoiceCode_like}
and t.INVOICE_CODE = #{invoiceCode}
and t.CUSTOMER_ID = #{customerId}
and t.CUSTOMER_NAME = #{customerName}
and t.INVOICE_AMOUNT = #{invoiceAmount}
and t.STATUS = #{status}
and t.INVOICE_TYPE_CODE = #{invoiceTypeCode}
and t.INVOICE_TYPE_NAME = #{invoiceTypeName}
and t.TAXATION_INVOICE = #{taxationInvoice}
and t.TAXATION_INVOICE_CODE = #{taxationInvoiceCode}
and to_char(t.INVOICE_TIME,'YYYY-MM-DD') >= #{startTime}
and to_char(t.INVOICE_TIME,'YYYY-MM-DD' ) <= #{endTime}
and to_char(t.INVOICE_TIME,'YYYY-MM-DD' )= to_char( #{invoiceTime},'YYYY-MM-DD')
) GROUP BY ID, HAS_NOT_RECEIPT_AMOUNT, COMPANY_NAME, COMPANY_ID, SYS_INVOICE_CODE, INVOICE_CODE, CUSTOMER_ID, CUSTOMER_NAME, INVOICE_AMOUNT, STATUS, INVOICE, INVOICE_TYPE_CODE, INVOICE_TYPE_NAME, TAXATION_INVOICE, TAXATION_INVOICE_CODE, INVOICE_TIME, REMARK, RED_STATUS, RED_STATUS_LABEL, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, IS_DEBTORPAYMENT, DEBTORPAYMENT_ID, UPDATE_TIME )
and SHIPVOYAGE_ITEM_ID LIKE #{shipvoyageItemId_like}
and IS_DEBTORPAYMENT = '1'
and IS_DEBTORPAYMENT = '0'
ORDER BY CREATE_TIME DESC

SELECT t1.ID, t1.STATEMENT AS statementId, t.CUSTOMER_ID AS "customerId", t.CUSTOMER_NAME AS "customerName", t.CARGO_NAME AS "cargoName", t.STATEMENT_NO AS STATEMENT_NO , "TYPE" AS type, t1.RATE_ITEM_CODE, t1.RATE_ITEM_NAME, t1.UNIT_CODE, t1.UNIT_NAME, t1."NUMBER" AS NUMBER_COUNT, t1."NUMBER2" AS NUMBER_COUNT2, t1.RATE AS pieceAmount, t1.AMOUNT AS amount, t1.INVOICE_AMOUNT AS invoiceAmount, t1.INVOICE_NUMBER AS invoiceNumber, CONCAT(CONCAT(t4.SHIP_NAME,'_'),t2.VOYAGE) AS SHIP_NAME_VOYAGE, t1.TAX, t1.TAX_AMOUNT, t1.RATE_ID, t3.CARGO_INFO_ID, t.SHIPVOYAGE_ID, t.SHIPVOYAGE_ITEM_ID, t.RECEIPT_REMARK, t.TAX_INVOICE_NAME, t.TAX_INVOICE_CODE, t4.SCN, t4.SHIP_NAME, t2.VOYAGE, t2.TRADE_TYPE, M2.DICT_VALUE AS "feeType", DECODE(t4.IMP_EXP, 'IN' ,'进口', 'OUT' ,'出口' , '' ) AS "impExp" FROM T_COST_STATEMENT t LEFT JOIN T_COST_STATEMENT_DETAIL t1 ON t.id = t1.STATEMENT LEFT join M_FEE_ITEM M1 on t1.RATE_ITEM_CODE = M1.ITEM_CD left join M_DICT_DATA M2 on M2.DICT_VALUE = M1.ITEM_TYPE_CD AND M2.DICT_TYPE='FEE_ITEM_TYPE' LEFT JOIN T_DIS_SHIPVOYAGE_ITEM t2 ON t.SHIPVOYAGE_ITEM_ID = t2.ID LEFT JOIN T_DIS_SHIPVOYAGE t4 ON t4.ID = t2.SHIPVOYAGE_ID LEFT JOIN T_BUS_TRUST_CARGO t3 ON t.TRUST_CARGO_ID = t3.ID
t.STATUS IN (31,40) and t.FINANCE_STATUS = '20' AND t1."NUMBER"-NVL(t1.INVOICE_NUMBER,0) > 0
AND t.COMPANY_ID = #{companyId,jdbcType=BIGINT}
AND t.CUSTOMER_ID = #{customerId}
AND t1.ID = #{id}
AND t.STATEMENT_NO LIKE #{statementNo_like}
AND t4.SCN LIKE #{scn_like}

update.foreach:
UPDATE
T_COST_STATEMENT_DETAIL
SET
INVOICE_NUMBER = #{item.invoiceNumber,jdbcType=DECIMAL},
INVOICE_AMOUNT = #{item.invoiceAmount,jdbcType=DECIMAL},
UPDATE_BY = #{item.loginUserId, jdbcType=BIGINT},
UPDATE_BY_NAME = #{item.loginUserName, jdbcType=VARCHAR},
UPDATE_TIME = #{item.now}

    id = #{item.id}


    ;

UPDATE
T_COST_STATEMENT
SET
STATUS = #{item.status},
UPDATE_BY = #{item.loginUserId, jdbcType=BIGINT},
UPDATE_BY_NAME = #{item.loginUserName, jdbcType=VARCHAR},
UPDATE_TIME = #{item.now}

    ID =  #{item.id}


    ;

