SET
    PAYMENT_AMOUNT = #{paymentAmount},
    PAYMENT_AMOUNT_BACK = #{paymentAmountBack}
where ID = #{id}

update T_DIS_SHIPVOYAGE  SET
    PAYMENT_AMOUNT = #{paymentAmount}
