mapper.select:
select
TCS.ID ID, TCS.statement_no statement_no, TCS.customer_name customer_name, TCS."TYPE" "TYPE", TCS.trust_cargo_id trust_cargo_id, TCS.shipvoyage_item_id shipvoyage_item_id, TCS.cargo_code cargo_code, TCS.cargo_name cargo_name, TCS.trade_type trade_type, TCS.status status, TCS.remark remark, to_char(TCS.create_TIME,'yyyy-MM-dd hh24:mi:ss') create_time, TCS.create_by_name create_by_name, TCSD.id detail_ID, tcsd.amount amount, tcsd."NUMBER" NUMBER1, TCSD.INVOICE_AMOUNT INVOICE_AMOUNT, TCSD.INVOICE_NUMBER INVOICE_NUMBER, TCSD.STATEMENT STATEMENT, to_char(TCSD.CREATE_TIME,'yyyy-MM-dd hh24:mi:ss') detail_Create_Time, TCSD.CREATE_BY_NAME detail_create_name
from T_COST_STATEMENT_DETAIL TCSD left join T_COST_STATEMENT TCS on TCSD.STATEMENT = TCS.ID where TCSD.id In ( select distinct TFID.STATEMENT_DETAIL_ID from T_FD_INVOICE_DETAIL TFID left join T_FD_INVOICE TFI on TFID.INVOICE_ID = TFI.ID where TFI.id = #{id,jdbcType=BIGINT} )
